(633, 'PAI', 'PAI', 12, 'Perhatikan ayat berikut! <img src=\"/unbk/pai/SOAL 12-01.jpg\" width=\"200\" height=\"auto\" /> Ayat di atas memerintahkan kepada umat Islam untuk ....', '', '', '', 'berijtihad dengan berpedoman kepada Allah swt. dan rasul-Nya', 'bekerja keras agar tercapai hidup yang baik', 'memiliki etika dan sopan santun dalam bermuamalah', 'memiliki sikap moderat dalam menjalani hidup sehari-hari', 'berpikir merenungkan ayat-ayat Alquran', '', '', '', '', '', '5', 0, 0, 0, 60, 5),
(629, 'PAI', 'PAI', 8, 'Menghidupkan kembali bagian-bagian dari nilai dan semangat Islam agar mampu menjawab tantangan zaman adalah urgensi ijtihad dilihat dari fungsi ....', '', '', '', 'al ruju\'', 'al ihyl', 'al inabah', 'far\'un', 'qat\'i', '', '', '', '', '', '2', 0, 0, 0, 60, 5),
(628, 'PAI', 'PAI', 7, 'Berikut merupakan penyebab seorang muslim berhak mendapat harta warisan, kecuali ....', '', '', '', 'hubungan sesama muslim', 'teman akrab', 'nasab', 'perkawinan', 'memerdekakan budak', '', '', '', '', '', '2', 0, 0, 0, 60, 5),
(627, 'PAI', 'PAI', 6, 'Kewajiban adalah tanggung jawab atau tugas yang harus dilaksanakan oleh seseorang sesuai dengan norma, aturan, atau hukum yang berlaku. Kewajiban yang harus dipenuhi ahli waris sebelum harta warisan dibagikan adalah ....', '', '', '', 'dosa jenazah dimaafkan kerabat yang masih hidup', 'membayar utang jenazah', 'menjual harta benda jenazah', 'jenazah dikebumikan', 'memandikan jenazah', '', '', '', '', '', '2', 0, 0, 0, 60, 5),
(626, 'PAI', 'PAI', 5, 'Pesan yang disampaikan orang yang akan meninggal dunia disebut ....', '', '', '', 'muhtador', 'talqin', 'wasiat', 'ikrar', 'janji', '', '', '', '', '', '3', 0, 0, 0, 60, 5),
(625, 'PAI', 'PAI', 4, 'Penerapan toleransi oleh masing-masing individu dalam masyarakat yang beragam, baik agama, kebudayaan, dan bahasa akan menimbulkan ....', '', '', '', 'keteraturan dan sikap ingin menang sendiri', 'ketenteraman dan kerukunan', 'perselisihan antaranggota masyarakat', 'percekcokan yang terjadi setiap saat', 'kekacauan dan ketidaktenteraman dalam kehidupan', '', '', '', '', '', '2', 0, 0, 0, 60, 5),
(622, 'PAI', 'PAI', 1, 'Salah satu langkah atau cara yang dapat menumbuhkan etos kerja adalah ....', '', '', '', 'menanamkan keimanan yang kuat dalam diri', 'mudah putus asa', 'melakukan segala sesuatu sesuai suasana hati', 'menghalalkan segala cara untuk mencapai keberhasilan', 'giat bekerja hingga lupa waktu', '', '', '', '', '', '2', 0, 0, 0, 60, 5),
(624, 'PAI', 'PAI', 3, 'Ciri-ciri orang berakal menurut surat Ali \'Imran ayat 191 adalah ....', '', '', '', 'banyak berdiskusi bersama teman', 'banyak mengobrol bersama teman', 'sering berkunjung ke rumah guru', 'selalu mengingat Allah swt.', 'selalu membaca buku', '', '', '', '', '', '4', 0, 0, 0, 60, 5),
(623, 'PAI', 'PAI', 2, 'Hukuman atau had bagi pelaku zina dapat dilaksanakan apabila terdapat ....', '', '', '', '2 saksi laki-laki dan 2 saksi perempuan', '3 saksi laki-laki yang meyakinkan', '4 saksi laki-laki yang fasik', '4 saksi perempuan yang adil', '4 saksi laki-laki yang adil', '', '', '', '', '', '5', 0, 0, 0, 60, 5),
