(4508, ' KIK PH', 'KIK PH NJ', 22, 'Apa tujuan utama kewirausahaan?', '', '', '', 'Memaksimalkan keuntungan dengan biaya rendah', 'Menciptakan peluang kerja dan nilai ekonomi', 'Mengurangi persaingan bisnis di pasar', 'Memperluas jaringan sosial', 'Menguasai pasar global', '', '', '', '', '', '3', 0, 0, 0, 0, 5),
(4507, ' KIK PH', 'KIK PH NJ', 21, 'Salah satu karakter penting dalam menangani keluhan pelanggan adalah:', '', '', '', 'Cepat defensif dan membela diri', 'Mengabaikan masukan pelanggan', 'Memiliki kemampuan mendengar dan memberikan solusi tepat', 'Membalas kritik dengan kritik', 'Meminta maaf tanpa memperbaiki masalah', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4506, ' KIK PH', 'KIK PH NJ', 20, 'Peluang usaha yang baik harus memenuhi kriteria berikut, KECUALI:', '', '', '', 'Realistis', 'Sesuai dengan tren pasar', 'Mudah ditiru kompetitor', 'Berpotensi menghasilkan keuntungan', 'Memiliki target pasar yang jelas', '', '', '', '', '', '3', 0, 0, 0, 0, 5),
(4505, ' KIK PH', 'KIK PH NJ', 19, 'Dalam kewirausahaan, \"peluang usaha\" dapat diartikan sebagai:', '', '', '', 'Modal besar yang tersedia untuk memulai bisnis', 'Ide bisnis yang sesuai dengan kebutuhan pasar', 'Rencana bisnis yang dibuat untuk investor', 'Hubungan baik dengan supplier dan pelanggan', 'Pengurangan risiko dalam bisnis', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4504, ' KIK PH', 'KIK PH NJ', 18, 'Mengapa kewirausahaan di bidang pariwisata dan perhotelan membutuhkan pemahaman budaya lokal?', '', '', '', 'Untuk menyesuaikan layanan dengan kebutuhan pelanggan lokal', 'Untuk mengurangi biaya promosi bisnis', 'Agar tidak perlu mempelajari tren global', 'Karena pelanggan tidak tertarik dengan budaya lain', 'Untuk menciptakan produk dan layanan yang lebih autentik', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4503, ' KIK PH', 'KIK PH NJ', 17, 'Berikut ini adalah faktor utama yang mendorong seseorang menjadi wirausahawan, KECUALI:', '', '', '', 'Keinginan untuk mendapatkan kebebasan finansial', 'Adanya peluang di pasar', 'Dorongan dari orang lain', 'Keinginan untuk mengikuti tren', 'Kemampuan memanfaatkan teknologi', '', '', '', '', '', '1', 0, 0, 0, 0, 5),
(4502, ' KIK PH', 'KIK PH NJ', 16, 'Salah satu tantangan utama dalam kewirausahaan di bidang perhotelan adalah:', '', '', '', 'Minimnya tenaga kerja di industri ini', 'Fluktuasi permintaan berdasarkan musim', 'Sulitnya menemukan lokasi strategis', 'Kurangnya peluang untuk inovasi', 'Tingginya persaingan dengan sektor Pendidikan', '', '', '', '', '', '4', 0, 0, 0, 0, 5),
(4501, ' KIK PH', 'KIK PH NJ', 15, 'Mengapa kreativitas penting bagi pengusaha di bidang pariwisata?', '', '', '', 'Untuk menurunkan biaya operasional', 'Untuk menciptakan pengalaman unik bagi pelanggan', 'Untuk menghindari kritik pelanggan', 'Untuk meningkatkan harga layanan tanpa inovasi', 'Untuk menggantikan peran karyawan', '', '', '', '', '', '1', 0, 0, 0, 0, 5),
(4500, ' KIK PH', 'KIK PH NJ', 14, 'Apa yang dimaksud dengan inovasi dalam kewirausahaan?', '', '', '', 'Memperluas usaha dengan modal besar', 'Meniru ide dari kompetitor', 'Membuat produk atau layanan baru yang bernilai tambah', 'Mengurangi biaya produksi tanpa mengubah kualitas', 'Menghindari persaingan pasar', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4499, ' KIK PH', 'KIK PH NJ', 13, 'Seorang wirausahawan biasanya memiliki karakteristik berikut, KECUALI:', '', '', '', 'Kreatif', 'Mandiri', 'Visioner', 'Berorientasi pada risiko rendah', 'Berani mengambil Keputusan', '', '', '', '', '', '5', 0, 0, 0, 0, 5),
(4498, ' KIK PH', 'KIK PH NJ', 12, 'Dalam pariwisata dan perhotelan, sifat pantang menyerah penting karena:', '', '', '', 'Bisnis di sektor ini cenderung mudah sukses tanpa tantangan', 'Pelanggan sering kali tidak peduli pada kualitas layanan', 'Banyak tantangan seperti perubahan musim, tren, dan permintaan pasar', 'Bisnis ini tidak memerlukan rencana jangka panjang', 'Pengusaha tidak perlu memikirkan reputasi', '', '', '', '', '', '3', 0, 0, 0, 0, 5),
(4497, ' KIK PH', 'KIK PH NJ', 11, 'Apa yang dimaksud dengan kewirausahaan di bidang pariwisata?', '', '', '', 'Membuka agen perjalanan dengan harga paling murah', 'Mengelola usaha yang menciptakan pengalaman unik bagi wisatawan', 'Menawarkan tiket pesawat dan akomodasi tanpa tambahan layanan', 'Menjalankan bisnis pariwisata tanpa memperhatikan tren pasar', 'Mengelola usaha dengan hanya mengikuti standar industry', '', '', '', '', '', '1', 0, 0, 0, 0, 5),
(4496, ' KIK PH', 'KIK PH NJ', 10, 'Analisis SWOT digunakan dalam memahami peluang usaha. Apa arti huruf \"W\" dalam SWOT?', '', '', '', 'Weakness', 'Wisdom', 'Wealth', 'Work', 'Willingness', '', '', '', '', '', '4', 0, 0, 0, 0, 5),
(4495, ' KIK PH', 'KIK PH NJ', 9, 'Salah satu karakter yang harus dimiliki oleh pengusaha di bidang perhotelan adalah:', '', '', '', 'Kemampuan memimpin dan berkoordinasi dengan tim', 'Ketidakpedulian terhadap perkembangan tren', 'Berani mengambil risiko tanpa perencanaan', 'Menghindari tantangan dalam operasional bisnis', 'Fokus pada keuntungan jangka pendek saja', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4494, ' KIK PH', 'KIK PH NJ', 8, 'Salah satu peluang kewirausahaan di bidang perhotelan adalah:', '', '', '', 'Membuka layanan restoran cepat saji', 'Mengembangkan aplikasi pemesanan hotel online', 'Mendirikan pabrik tekstil untuk kebutuhan hotel', 'Menyediakan layanan pengangkutan logistik', 'Mengelola usaha retail pakaian untuk wisatawan', '', '', '', '', '', '1', 0, 0, 0, 0, 5),
(4493, ' KIK PH', 'KIK PH NJ', 7, 'Dalam kewirausahaan, pengambilan risiko dapat diartikan sebagai:', '', '', '', 'Mengambil keputusan tanpa analisis', 'Menjalankan bisnis dengan keuntungan besar tanpa persiapan', 'Kemauan untuk mencoba sesuatu yang baru meskipun tidak pasti', 'Menghindari kerugian sebanyak mungkin', 'Menjalankan bisnis berdasarkan tren saja', '', '', '', '', '', '4', 0, 0, 0, 0, 5),
(4492, ' KIK PH', 'KIK PH NJ', 6, 'Apa yang dimaksud dengan kewirausahaan?', '', '', '', 'Kemampuan mengelola keuangan Perusahaan', 'Aktivitas membeli dan menjual produk', 'Proses menciptakan nilai melalui inovasi dan pengambilan risiko', 'Aktivitas bekerja untuk orang lain', 'Proses memimpin tim tanpa modal', '', '', '', '', '', '3', 0, 0, 0, 0, 5),
(4491, ' KIK PH', 'KIK PH NJ', 5, 'Salah satu perbedaan utama antara pengusaha (businessman) dan wirausahawan (entrepreneur) adalah:', '', '', '', 'Wirausahawan cenderung mengutamakan kuantitas dibanding kualitas', 'Pengusaha lebih berorientasi pada solusi, wirausahawan pada keuntungan', 'Wirausahawan menciptakan inovasi, pengusaha fokus pada operasional', 'Wirausahawan bekerja untuk orang lain, pengusaha untuk diri sendiri', 'Pengusaha tidak berani mengambil risiko, wirausahawan selalu menghindari risiko', '', '', '', '', '', '5', 0, 0, 0, 0, 5),
(4490, ' KIK PH', 'KIK PH NJ', 4, 'Apa keunggulan utama membuka usaha berbasis homestay di sektor pariwisata?', '', '', '', 'Modal yang besar untuk operasional', 'Memberikan pengalaman lokal yang autentik bagi wisatawan', 'Fokus pada akomodasi tanpa melibatkan layanan tambahan', 'Menargetkan pelanggan dari kalangan atas saja', 'Mengandalkan agen perjalanan untuk semua reservasi', '', '', '', '', '', '2', 0, 0, 0, 0, 5),
(4489, ' KIK PH', 'KIK PH NJ', 3, 'Berikut ini adalah contoh inovasi dalam kewirausahaan di bidang perhotelan:', '', '', '', 'Menawarkan diskon besar setiap bulan', 'Membuka hotel dengan konsep ramah lingkungan', 'Menjual produk oleh-oleh khas daerah', 'Menyediakan kamar tanpa fasilitas tambahan', 'Fokus pada hotel di kota besar saja', '', '', '', '', '', '3', 0, 0, 0, 0, 5),
(4488, ' KIK PH', 'KIK PH NJ', 2, 'Microsite s.id sering digunakan oleh siapa?', '', '', '', 'Desainer grafis untuk proyek 3D', 'Influencer, bisnis kecil, dan organisasi untuk berbagi tautan', 'Pengembang perangkat lunak untuk hosting aplikasi', 'Fotografer profesional untuk galeri foto', 'Penulis untuk membuat e-book interaktif', '', '', '', '', '', '5', 0, 0, 0, 0, 5),
