(5489, 'SMK4', 'BIP', 1, 'Apa yang dimaksud dengan Microsite pada platform s.id?', '', '', '', 'Halaman kecil yang dibuat di website utama', 'Platform untuk membuat blog pribadi', 'Halaman website sederhana yang dirancang untuk kebutuhan tertentu', 'Sistem pengelolaan media sosial otomatis', 'Template desain website untuk e-commerce', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5490, 'SMK4', 'BIP', 2, 'Microsite s.id sering digunakan oleh siapa?', '', '', '', 'Desainer grafis untuk proyek 3D', 'Influencer, bisnis kecil, dan organisasi untuk berbagi tautan', 'Pengembang perangkat lunak untuk hosting aplikasi', 'Fotografer profesional untuk galeri foto', 'Penulis untuk membuat e-book interaktif', '', '', '', '', '', '5', 0, NULL, NULL, NULL, 5),
(5491, 'SMK4', 'BIP', 3, 'Berikut ini adalah contoh inovasi dalam kewirausahaan di bidang perhotelan:', '', '', '', 'Menawarkan diskon besar setiap bulan', 'Membuka hotel dengan konsep ramah lingkungan', 'Menjual produk oleh-oleh khas daerah', 'Menyediakan kamar tanpa fasilitas tambahan', 'Fokus pada hotel di kota besar saja', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5492, 'SMK4', 'BIP', 4, 'Apa keunggulan utama membuka usaha berbasis homestay di sektor pariwisata?', '', '', '', 'Modal yang besar untuk operasional', 'Memberikan pengalaman lokal yang autentik bagi wisatawan', 'Fokus pada akomodasi tanpa melibatkan layanan tambahan', 'Menargetkan pelanggan dari kalangan atas saja', 'Mengandalkan agen perjalanan untuk semua reservasi', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5493, 'SMK4', 'BIP', 5, 'Salah satu perbedaan utama antara pengusaha (businessman) dan wirausahawan (entrepreneur) adalah:', '', '', '', 'Wirausahawan cenderung mengutamakan kuantitas dibanding kualitas', 'Pengusaha lebih berorientasi pada solusi, wirausahawan pada keuntungan', 'Wirausahawan menciptakan inovasi, pengusaha fokus pada operasional', 'Wirausahawan bekerja untuk orang lain, pengusaha untuk diri sendiri', 'Pengusaha tidak berani mengambil risiko, wirausahawan selalu menghindari risiko', '', '', '', '', '', '5', 0, NULL, NULL, NULL, 5),
(5494, 'SMK4', 'BIP', 6, 'Apa yang dimaksud dengan kewirausahaan?', '', '', '', 'Kemampuan mengelola keuangan Perusahaan', 'Aktivitas membeli dan menjual produk', 'Proses menciptakan nilai melalui inovasi dan pengambilan risiko', 'Aktivitas bekerja untuk orang lain', 'Proses memimpin tim tanpa modal', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5495, 'SMK4', 'BIP', 7, 'Dalam kewirausahaan, pengambilan risiko dapat diartikan sebagai:', '', '', '', 'Mengambil keputusan tanpa analisis', 'Menjalankan bisnis dengan keuntungan besar tanpa persiapan', 'Kemauan untuk mencoba sesuatu yang baru meskipun tidak pasti', 'Menghindari kerugian sebanyak mungkin', 'Menjalankan bisnis berdasarkan tren saja', '', '', '', '', '', '4', 0, NULL, NULL, NULL, 5),
(5496, 'SMK4', 'BIP', 8, 'Salah satu peluang kewirausahaan di bidang perhotelan adalah:', '', '', '', 'Membuka layanan restoran cepat saji', 'Mengembangkan aplikasi pemesanan hotel online', 'Mendirikan pabrik tekstil untuk kebutuhan hotel', 'Menyediakan layanan pengangkutan logistik', 'Mengelola usaha retail pakaian untuk wisatawan', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5497, 'SMK4', 'BIP', 9, 'Salah satu karakter yang harus dimiliki oleh pengusaha di bidang perhotelan adalah:', '', '', '', 'Kemampuan memimpin dan berkoordinasi dengan tim', 'Ketidakpedulian terhadap perkembangan tren', 'Berani mengambil risiko tanpa perencanaan', 'Menghindari tantangan dalam operasional bisnis', 'Fokus pada keuntungan jangka pendek saja', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5498, 'SMK4', 'BIP', 10, 'Analisis SWOT digunakan dalam memahami peluang usaha. Apa arti huruf \"W\" dalam SWOT?', '', '', '', 'Weakness', 'Wisdom', 'Wealth', 'Work', 'Willingness', '', '', '', '', '', '4', 0, NULL, NULL, NULL, 5),
(5499, 'SMK4', 'BIP', 11, 'Apa yang dimaksud dengan kewirausahaan di bidang pariwisata?', '', '', '', 'Membuka agen perjalanan dengan harga paling murah', 'Mengelola usaha yang menciptakan pengalaman unik bagi wisatawan', 'Menawarkan tiket pesawat dan akomodasi tanpa tambahan layanan', 'Menjalankan bisnis pariwisata tanpa memperhatikan tren pasar', 'Mengelola usaha dengan hanya mengikuti standar industry', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5500, 'SMK4', 'BIP', 12, 'Dalam pariwisata dan perhotelan, sifat pantang menyerah penting karena:', '', '', '', 'Bisnis di sektor ini cenderung mudah sukses tanpa tantangan', 'Pelanggan sering kali tidak peduli pada kualitas layanan', 'Banyak tantangan seperti perubahan musim, tren, dan permintaan pasar', 'Bisnis ini tidak memerlukan rencana jangka panjang', 'Pengusaha tidak perlu memikirkan reputasi', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5501, 'SMK4', 'BIP', 13, 'Seorang wirausahawan biasanya memiliki karakteristik berikut, KECUALI:', '', '', '', 'Kreatif', 'Mandiri', 'Visioner', 'Berorientasi pada risiko rendah', 'Berani mengambil Keputusan', '', '', '', '', '', '5', 0, NULL, NULL, NULL, 5),
(5502, 'SMK4', 'BIP', 14, 'Apa yang dimaksud dengan inovasi dalam kewirausahaan?', '', '', '', 'Memperluas usaha dengan modal besar', 'Meniru ide dari kompetitor', 'Membuat produk atau layanan baru yang bernilai tambah', 'Mengurangi biaya produksi tanpa mengubah kualitas', 'Menghindari persaingan pasar', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5503, 'SMK4', 'BIP', 15, 'Mengapa kreativitas penting bagi pengusaha di bidang pariwisata?', '', '', '', 'Untuk menurunkan biaya operasional', 'Untuk menciptakan pengalaman unik bagi pelanggan', 'Untuk menghindari kritik pelanggan', 'Untuk meningkatkan harga layanan tanpa inovasi', 'Untuk menggantikan peran karyawan', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5504, 'SMK4', 'BIP', 16, 'Salah satu tantangan utama dalam kewirausahaan di bidang perhotelan adalah:', '', '', '', 'Minimnya tenaga kerja di industri ini', 'Fluktuasi permintaan berdasarkan musim', 'Sulitnya menemukan lokasi strategis', 'Kurangnya peluang untuk inovasi', 'Tingginya persaingan dengan sektor Pendidikan', '', '', '', '', '', '4', 0, NULL, NULL, NULL, 5),
(5505, 'SMK4', 'BIP', 17, 'Berikut ini adalah faktor utama yang mendorong seseorang menjadi wirausahawan, KECUALI:', '', '', '', 'Keinginan untuk mendapatkan kebebasan finansial', 'Adanya peluang di pasar', 'Dorongan dari orang lain', 'Keinginan untuk mengikuti tren', 'Kemampuan memanfaatkan teknologi', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5506, 'SMK4', 'BIP', 18, 'Mengapa kewirausahaan di bidang pariwisata dan perhotelan membutuhkan pemahaman budaya lokal?', '', '', '', 'Untuk menyesuaikan layanan dengan kebutuhan pelanggan lokal', 'Untuk mengurangi biaya promosi bisnis', 'Agar tidak perlu mempelajari tren global', 'Karena pelanggan tidak tertarik dengan budaya lain', 'Untuk menciptakan produk dan layanan yang lebih autentik', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5507, 'SMK4', 'BIP', 19, 'Dalam kewirausahaan, \"peluang usaha\" dapat diartikan sebagai:', '', '', '', 'Modal besar yang tersedia untuk memulai bisnis', 'Ide bisnis yang sesuai dengan kebutuhan pasar', 'Rencana bisnis yang dibuat untuk investor', 'Hubungan baik dengan supplier dan pelanggan', 'Pengurangan risiko dalam bisnis', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5508, 'SMK4', 'BIP', 20, 'Peluang usaha yang baik harus memenuhi kriteria berikut, KECUALI:', '', '', '', 'Realistis', 'Sesuai dengan tren pasar', 'Mudah ditiru kompetitor', 'Berpotensi menghasilkan keuntungan', 'Memiliki target pasar yang jelas', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5509, 'SMK4', 'BIP', 21, 'Salah satu karakter penting dalam menangani keluhan pelanggan adalah:', '', '', '', 'Cepat defensif dan membela diri', 'Mengabaikan masukan pelanggan', 'Memiliki kemampuan mendengar dan memberikan solusi tepat', 'Membalas kritik dengan kritik', 'Meminta maaf tanpa memperbaiki masalah', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5510, 'SMK4', 'BIP', 22, 'Apa tujuan utama kewirausahaan?', '', '', '', 'Memaksimalkan keuntungan dengan biaya rendah', 'Menciptakan peluang kerja dan nilai ekonomi', 'Mengurangi persaingan bisnis di pasar', 'Memperluas jaringan sosial', 'Menguasai pasar global', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5511, 'SMK4', 'BIP', 23, 'Apa yang menjadi ciri khas utama seorang pengusaha di bidang pariwisata dan perhotelan?', '', '', '', 'Tidak terlalu memperhatikan pelayanan', 'Selalu berorientasi pada kepuasan pelanggan', 'Mengutamakan keuntungan dibandingkan kualitas', 'Fokus pada produk tanpa mempertimbangkan pengalaman pelanggan', 'Mengabaikan umpan balik dari pelanggan', '', '', '', '', '', '5', 0, NULL, NULL, NULL, 5),
(5512, 'SMK4', 'BIP', 24, 'Usaha “Roti MOKKOH” memproduksi 300 bungkus roti. Biaya: <BR><table border=\"0\"><tr><td>Tepung & susu </td><td>: Rp700.000,00 </td></tr><tr><td>Kemasan </td><td>: Rp150.000,00 </td></tr><tr><td>Tenaga kerja </td><td>: Rp450.000,00</td></tr><tr><td>Overhead </td><td>: Rp100.000,00 </td></tr></table><BR>15 bungkus rusak. Berapakah biaya produksi per bungkus layak jual?', '', '', '', 'Rp. 4.700,00', 'Rp. 4.800,00', 'Rp. 4.900,00', 'Rp. 5.100,00', 'Rp. 5.200,00', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5513, 'SMK4', 'BIP', 25, 'Kelompok membuat “Sabun Cair Cendana”. Biaya: <BR><table border=\"0\"><tr><td>Bahan kimia & pewangi </td><td>: Rp800.000,00 </td></tr><tr><td>Botol & label </td><td>: Rp250.000,00 </td></tr><tr><td>Tenaga kerja </td><td>: Rp450.000,00 </td></tr><tr><td>Overhead </td><td>: Rp150.000,00 </td></tr></table><BR>Produksi 400 botol, 20 rusak. Biaya produksi per botol layak jual adalah….', '', '', '', 'Rp. 4.100,00', 'Rp. 4.300,00', 'Rp. 4.500,00', 'Rp. 4.700,00', 'Rp. 4.800,00', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5514, 'SMK4', 'BIP', 26, 'Berikut pernyataan yang tepat mengenai perbedaan harga pokok produksi dan harga pokok penjualan adalah....', '', '', '', 'Harga pokok produksi dihitung sebelum penjualan sedangkan harga pokok penjualan dihitung setelah terjadi transaksi penjualan', 'Pada harga pokok penjualan telah ditambahkan jumlah keuntungan yang diinginka n perusahaan sedangkan pada harga pokok produksi tidak ditambahkan', 'Harga pokok penjualan digunakan dalam perusahaan jasa sedangkan harga pokok produksi digunakan dalam perusahaan manufaktur', 'Harga pokok produksi memuat unsur biaya overhead pabrik sedangkan harga pokok penjualan tidak', 'Pada harga pokok penjualan terdapat unsur fix cost dan variable cost sedangkan pada harga poko produksi hanya terdapat unsur direct material dan fix cost', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5515, 'SMK4', 'BIP', 27, 'Biaya produksi per unit dihitung dengan membagi total biaya produksi dengan....', '', '', '', 'Total unit yang dipesan', 'Biaya produksi per satuan', 'Nilai jual produk', 'Biaya overhead pabrik', 'Biaya langsung', '', '', '', '', '', '3', 0, NULL, NULL, NULL, 5),
(5516, 'SMK4', 'BIP', 28, 'Total pendapatan dapat dihitung dengan cara mengalikan jumlah seluruh produk yang dihasilkan dengan....', '', '', '', 'Biaya rata-rata', 'Biaya marginal', 'Harga jual produk', 'Penerimaan marginal', 'Total biaya tetap', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5517, 'SMK4', 'BIP', 29, 'Berikut termasuk hal-hal yang perlu dipertimbangkan dalam pengambilan keputusan oleh seorang manajer, kecuali......', '', '', '', 'Jumlah penjualan minimal yang harus dipertahankan agar perusahaan tidak mengalami kerugian', 'Jumlah keuntungan yang diharapkan oleh pemangku kepentingan di perusahaan', 'Seberapa jauh berkurangnya penjualan agar perusahaan tidak menderita kerugian', 'Jumlah penjualan yang harus dicapai untuk memperoleh keuntungan tertentu', 'Untuk mengetahui bagaimana efek perubahan harga jual,biaya dan volume penjualan terhadap keuntungan yang diperoleh', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5518, 'SMK4', 'BIP', 30, 'Harga jual suatu produk merupakan perwujudan biaya yang dikeluarkan dalam mengolah produk tersebut. Hal tersebut menjadi dasar penentuan metode....', '', '', '', 'Laba kontribusi', 'Biaya total', 'Harga seimbang', 'Nilai jual eksklusif', 'Nilai jual relatif', '', '', '', '', '', '4', 0, NULL, NULL, NULL, 5),
(5519, 'SMK4', 'BIP', 31, 'Hotel antariksa merupakan perusahaan yang bergerak dibidang jasa berupa penjualan kamar, diketahui fixed cost sebesar Rp. 448.000.000, variable cost Rp. 165.000 dan harga jual tiket Rp. 805.000 per paket. Jumlah kamar yang harus dijual untuk mencapai titik BEP adalah....kamar', '', '', '', '500', '600', '700', '800', '900', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5520, 'SMK4', 'BIP', 32, 'Jika perusahaan akan memproduksi dan menjual lebih dari satu jenis produk, aspek yg terdapat didalamnya adalah…', '', '', '', 'jenis produk', 'cara', 'tempat', 'kombinasi produk', 'pemasaran', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5521, 'SMK4', 'BIP', 33, 'Suatu daftar persyartan yang diperlukan untuk memegang jabatan/pekerjaan tertentu, yaitu tingkat pendidikan, keterampilan, kepribadian, dan lain-lain disebut………pekerjaan.', '', '', '', 'spesifikasi', 'deskripsi', 'tanggung jawab', 'deadline', 'target', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
