(5524, 'SMK4', 'BIP', 36, 'Gabungan dari beberapa unit atau elemen yang saling berhubungan dan saling menunjang untuk melaksanakan proses produksi dalam suatu perusahaan disebut …..', '', '', '', 'manajemen produksi', 'perencanaan produksi', 'sistem produksi', 'sistem pemasaran', 'kombinasi produk', '', '', '', '', '', '1', 0, NULL, NULL, NULL, 5),
(5525, 'SMK4', 'BIP', 37, 'Salah satu pola/kebijakan produksi yang mana naik turunya penjualan akan berakibat langsung pada naik turunya baik produksi maupun persediaan adalah pola…', '', '', '', 'moderat', 'terus-menerus', 'bergelombang', 'konstan', 'terputus-putus', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
(5526, 'SMK4', 'BIP', 38, 'Segala sesuatu, baik berupa benda nyata maupun bukan benda nyata, yang dibutuhka manusia untuk kelangsungan hidupnya disebut ….', '', '', '', 'konsumsi', 'produksi', 'sumber daya', 'modal', 'kekayaan', '', '', '', '', '', '2', 0, NULL, NULL, NULL, 5),
